   216→size_t zmalloc_used_memory(void) {
   217→    size_t um;
   218→    atomicGet(used_memory,um);
   219→    return um;
   220→}
   221→
   222→void zmalloc_set_oom_handler(void (*oom_handler)(size_t)) {
   223→    zmalloc_oom_handler = oom_handler;
   224→}
   225→
   226→/* Get the RSS information in an OS-specific way.
   227→ *
   228→ * WARNING: the function zmalloc_get_rss() is not designed to be fast
   229→ * and may not be called in the busy loops where Redis tries to release
   230→ * memory expiring or swapping out objects.
   231→ *
   232→ * For this kind of "fast RSS reporting" usages use instead the
   233→ * function RedisEstimateRSS() that is a much faster (and less precise)
   234→ * version of the function. */
   235→
   236→#if defined(HAVE_PROC_STAT)
   237→#include <unistd.h>
   238→#include <sys/types.h>
   239→#include <sys/stat.h>
   240→#include <fcntl.h>
   241→
   242→size_t zmalloc_get_rss(void) {
   243→    int page = sysconf(_SC_PAGESIZE);
   244→    size_t rss;
   245→    char buf[4096];
   246→    char filename[256];
   247→    int fd, count;
   248→    char *p, *x;
   249→
   250→    snprintf(filename,256,"/proc/%d/stat",getpid());
   251→    if ((fd = open(filename,O_RDONLY)) == -1) return 0;
   252→    if (read(fd,buf,4096) <= 0) {
   253→        close(fd);
   254→        return 0;
   255→    }
   256→    close(fd);
   257→
   258→    p = buf;
   259→    count = 23; /* RSS is the 24th field in /proc/<pid>/stat */
   260→    while(p && count--) {
   261→        p = strchr(p,' ');
   262→        if (p) p++;
   263→    }
   264→    if (!p) return 0;
   265→    x = strchr(p,' ');
   266→    if (!x) return 0;
   267→    *x = '\0';
   268→
   269→    rss = strtoll(p,NULL,10);
   270→    rss *= page;
   271→    return rss;
   272→}
   273→#elif defined(HAVE_TASKINFO)
   274→#include <unistd.h>
   275→#include <stdio.h>
   276→#include <stdlib.h>
   277→#include <sys/types.h>
   278→#include <sys/sysctl.h>
   279→#include <mach/task.h>
   280→#include <mach/mach_init.h>
   281→
   282→size_t zmalloc_get_rss(void) {
   283→    task_t task = MACH_PORT_NULL;
   284→    struct task_basic_info t_info;
   285→    mach_msg_type_number_t t_info_count = TASK_BASIC_INFO_COUNT;
   286→
   287→    if (task_for_pid(current_task(), getpid(), &task) != KERN_SUCCESS)
   288→        return 0;
   289→    task_info(task, TASK_BASIC_INFO, (task_info_t)&t_info, &t_info_count);
   290→
   291→    return t_info.resident_size;
   292→}
   293→#else
   294→size_t zmalloc_get_rss(void) {
   295→    /* If we can't get the RSS in an OS-specific way for this system just
   296→     * return the memory usage we estimated in zmalloc()..
   297→     *
   298→     * Fragmentation will appear to be always 1 (no fragmentation)
   299→     * of course... */
   300→    return zmalloc_used_memory();
   301→}
   302→#endif
   303→
   304→#if defined(USE_JEMALLOC)
   305→int zmalloc_get_allocator_info(size_t *allocated,
   306→                               size_t *active,
   307→                               size_t *resident) {
   308→    uint64_t epoch = 1;
   309→    size_t sz;
   310→    *allocated = *resident = *active = 0;
   311→    /* Update the statistics cached by mallctl. */
   312→    sz = sizeof(epoch);
   313→    je_mallctl("epoch", &epoch, &sz, &epoch, sz);
   314→    sz = sizeof(size_t);
   315→    /* Unlike RSS, this does not include RSS from shared libraries and other non
   316→     * heap mappings. */
   317→    je_mallctl("stats.resident", resident, &sz, NULL, 0);
   318→    /* Unlike resident, this doesn't not include the pages jemalloc reserves
   319→     * for re-use (purge will clean that). */
   320→    je_mallctl("stats.active", active, &sz, NULL, 0);
   321→    /* Unlike zmalloc_used_memory, this matches the stats.resident by taking
   322→     * into account all allocations done by this process (not only zmalloc). */
   323→    je_mallctl("stats.allocated", allocated, &sz, NULL, 0);
   324→    return 1;
   325→}
   326→#else
   327→int zmalloc_get_allocator_info(size_t *allocated,
   328→                               size_t *active,
   329→                               size_t *resident) {
   330→    *allocated = *resident = *active = 0;
   331→    return 1;
   332→}
   333→#endif
   334→
   335→/* Get the sum of the specified field (converted form kb to bytes) in
   336→ * /proc/self/smaps. The field must be specified with trailing ":" as it
   337→ * apperas in the smaps output.
   338→ *
   339→ * If a pid is specified, the information is extracted for such a pid,
   340→ * otherwise if pid is -1 the information is reported is about the
   341→ * current process.
   342→ *
   343→ * Example: zmalloc_get_smap_bytes_by_field("Rss:",-1);
   344→ */
   345→#if defined(HAVE_PROC_SMAPS)
   346→size_t zmalloc_get_smap_bytes_by_field(char *field, long pid) {
   347→    char line[1024];
   348→    size_t bytes = 0;
   349→    int flen = strlen(field);
   350→    FILE *fp;
   351→
   352→    if (pid == -1) {
   353→        fp = fopen("/proc/self/smaps","r");
   354→    } else {
   355→        char filename[128];
   356→        snprintf(filename,sizeof(filename),"/proc/%ld/smaps",pid);
   357→        fp = fopen(filename,"r");
   358→    }
   359→
   360→    if (!fp) return 0;
   361→    while(fgets(line,sizeof(line),fp) != NULL) {
   362→        if (strncmp(line,field,flen) == 0) {
   363→            char *p = strchr(line,'k');
   364→            if (p) {
   365→                *p = '\0';
   366→                bytes += strtol(line+flen,NULL,10) * 1024;
   367→            }
   368→        }
   369→    }
   370→    fclose(fp);
   371→    return bytes;
   372→}
   373→#else
   374→size_t zmalloc_get_smap_bytes_by_field(char *field, long pid) {
   375→    ((void) field);
   376→    ((void) pid);
   377→    return 0;
   378→}
   379→#endif
   380→
   381→size_t zmalloc_get_private_dirty(long pid) {
   382→    return zmalloc_get_smap_bytes_by_field("Private_Dirty:",pid);
   383→}
   384→
   385→/* Returns the size of physical memory (RAM) in bytes.
   386→ * It looks ugly, but this is the cleanest way to achieve cross platform results.
   387→ * Cleaned up from:
   388→ *
   389→ * http://nadeausoftware.com/articles/2012/09/c_c_tip_how_get_physical_memory_size_system
   390→ *
   391→ * Note that this function:
   392→ * 1) Was released under the following CC attribution license:
   393→ *    http://creativecommons.org/licenses/by/3.0/deed.en_US.
   394→ * 2) Was originally implemented by David Robert Nadeau.
   395→ * 3) Was modified for Redis by Matt Stancliff.
   396→ * 4) This note exists in order to comply with the original license.
   397→ */
   398→size_t zmalloc_get_memory_size(void) {
   399→#if defined(__unix__) || defined(__unix) || defined(unix) || \
   400→    (defined(__APPLE__) && defined(__MACH__))
   401→#if defined(CTL_HW) && (defined(HW_MEMSIZE) || defined(HW_PHYSMEM64))
   402→    int mib[2];
   403→    mib[0] = CTL_HW;
   404→#if defined(HW_MEMSIZE)
   405→    mib[1] = HW_MEMSIZE;            /* OSX. --------------------- */
   406→#elif defined(HW_PHYSMEM64)
